import React, { Component } from "react";
import "./index.css";
import defaultProfileImg from "./image/1.jpg";

class App extends Component {
    constructor(props) {
        super(props);

        // Load saved data from localStorage
        const savedProfile = JSON.parse(localStorage.getItem("userProfile"));
        const savedImg = localStorage.getItem("profileImg");

        if (savedProfile) {
            this.state = savedProfile;

            if (savedImg) {
                this.state.profileImg = savedImg;
            }
        } 
        else {
            this.state = {
                firstName: "",
                lastName: "",
                mobile: "",
                password: "",
                email: "",
                registeredDate: "",
                address1: "",
                address2: "",
                province: "",
                district: "",
                showPassword: false,
                profileImg: savedImg ? savedImg : defaultProfileImg,
            };
        }

        this.fileInputRef = React.createRef();
    }

    handleChange(event) {
        const name = event.target.name;
        const value = event.target.value;
        const newState = this.state;
        newState[name] = value;
        this.setState(newState);
    }

    togglePassword() {
        this.setState({ showPassword: !this.state.showPassword });
    }

    handleProfileImgChange(event) {
        const file = event.target.files[0];
        if (file) {
            const reader = new FileReader();
            const that = this;
            reader.onload = function (e) {
                localStorage.setItem("profileImg", e.target.result);
                const newState = that.state;
                newState.profileImg = e.target.result;
                that.setState(newState);
            };
            reader.readAsDataURL(file);
        }
    }

    handleSubmit(event) {
        event.preventDefault();

        const data = this.state;

        if (
            data.firstName === "" ||
            data.lastName === "" ||
            data.mobile === "" ||
            data.password === "" ||
            data.email === "" ||
            data.registeredDate === "" ||
            data.address1 === "" ||
            data.province === "" ||
            data.district === ""
        ) {
            alert("⚠️ Please fill all required fields before updating your profile.");
            return;
        }

        localStorage.setItem("userProfile", JSON.stringify(this.state));
        alert("✅ Profile updated successfully!");
    }

    render() {
        return (
            <div
                style={{
                    display: "flex",
                    justifyContent: "center",
                    alignItems: "flex-start",
                    minHeight: "100vh",
                    background: "#f7f7f7",
                }}
            >
                {/* Left side */}
                <div
                    style={{
                        width: 320,
                        background: "#fff",
                        borderRadius: 12,
                        boxShadow: "0 2px 8px #eee",
                        padding: 32,
                        marginRight: 32,
                        textAlign: "center",
                    }}
                >
                    <img
                        src={this.state.profileImg}
                        alt="Profile"
                        style={{
                            width: 120,
                            height: 120,
                            borderRadius: "50%",
                            objectFit: "cover",
                            marginBottom: 16,
                        }}
                    />
                    <h4 style={{ margin: "8px 0 4px" }}>
                        {this.state.firstName || "Your Name"}
                    </h4>
                    <div style={{ color: "#888", fontSize: 15, marginBottom: 24 }}>
                        {this.state.email || "your@email.com"}
                    </div>
                    <input
                        type="file"
                        accept="image/*"
                        style={{ display: "none" }}
                        ref={this.fileInputRef}
                        onChange={this.handleProfileImgChange.bind(this)}
                    />
                    <button
                        className="btn btn-primary"
                        onClick={() => this.fileInputRef.current.click()}
                    >
                        Update Profile Image
                    </button>
                </div>

                {/* Right side */}
                <div
                    style={{
                        flex: 1,
                        background: "#fff",
                        borderRadius: 12,
                        boxShadow: "0 2px 8px #eee",
                        padding: 32,
                        maxWidth: 600,
                    }}
                >
                    <h3 style={{ marginBottom: 24 }}>Profile Settings</h3>

                    <form onSubmit={this.handleSubmit.bind(this)}>
                        <div className="row mb-3">
                            <div className="col">
                                <label>First Name</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    name="firstName"
                                    value={this.state.firstName}
                                    onChange={this.handleChange.bind(this)}
                                />
                            </div>

                            <div className="col">
                                <label>Last Name</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    name="lastName"
                                    value={this.state.lastName}
                                    onChange={this.handleChange.bind(this)}
                                />
                            </div>
                        </div>

                        <div className="mb-3">
                            <label>Mobile</label>
                            <input
                                type="text"
                                className="form-control"
                                name="mobile"
                                value={this.state.mobile}
                                onChange={this.handleChange.bind(this)}
                            />
                        </div>

                        <div className="mb-3" style={{ position: "relative" }}>
                            <label>Password</label>
                            <input
                                type={this.state.showPassword ? "text" : "password"}
                                className="form-control"
                                name="password"
                                value={this.state.password}
                                onChange={this.handleChange.bind(this)}
                            />
                            <button
                                type="button"
                                className="btn btn-outline-secondary"
                                style={{
                                    position: "absolute",
                                    right: 8,
                                    top: 32,
                                    padding: "2px 8px",
                                }}
                                onClick={this.togglePassword.bind(this)}
                            >
                                {this.state.showPassword ? "Hide" : "Show"}
                            </button>
                        </div>

                        <div className="mb-3">
                            <label>Email</label>
                            <input
                                type="email"
                                className="form-control"
                                name="email"
                                value={this.state.email}
                                onChange={this.handleChange.bind(this)}
                            />
                        </div>

                        <div className="mb-3">
                            <label>Registered Date</label>
                            <input
                                type="text"
                                className="form-control"
                                name="registeredDate"
                                value={this.state.registeredDate}
                                onChange={this.handleChange.bind(this)}
                                placeholder="YYYY-MM-DD HH:MM:SS"
                            />
                        </div>

                        <div className="mb-3">
                            <label>Address Line 1</label>
                            <input
                                type="text"
                                className="form-control"
                                name="address1"
                                value={this.state.address1}
                                onChange={this.handleChange.bind(this)}
                            />
                        </div>

                        <div className="mb-3">
                            <label>Address Line 2</label>
                            <input
                                type="text"
                                className="form-control"
                                name="address2"
                                value={this.state.address2}
                                onChange={this.handleChange.bind(this)}
                            />
                        </div>

                        <div className="row mb-3">
                            <div className="col">
                                <label>Province</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    name="province"
                                    value={this.state.province}
                                    onChange={this.handleChange.bind(this)}
                                />
                            </div>

                            <div className="col">
                                <label>District</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    name="district"
                                    value={this.state.district}
                                    onChange={this.handleChange.bind(this)}
                                />
                            </div>
                        </div>

                        <button type="submit" className="btn btn-success mt-2">
                            Update Profile
                        </button>
                    </form>
                </div>
            </div>
        );
    }
}

export default App;
